IF ((NOT(__ISVALIDREF(lPackSystem))) OR
	(NOT(__ISVALIDREF(lPackMovement))) OR
	(NOT(__ISVALIDREF(lPackReportable))) OR
	(NOT(__ISVALIDREF(lPackSpreader))) OR
	(NOT(__ISVALIDREF(lPackUICommand))) OR
	(NOT(__ISVALIDREF(lPackProvider)))) THEN
	gCodeErrorHandler(pMessage:=CONCAT('null reference in ',lIdentity));
END_IF

lPackTimer.lEnable := TRUE;
lPackTimer.lPeriod := T#60MS;
lPackTimer.initialize();

lPLCOutgoingChannel.register(ADR(lPackSystem)); // foobar particle reorganization
lPLCOutgoingChannel.register(ADR(lPackMovement));
lPLCOutgoingChannel.register(ADR(lPackReportable));
lPLCOutgoingChannel.register(ADR(lPackSpreader));
lPLCOutgoingChannel.initialize();

lPLCIncomingChannel.register(ADR(lPackUICommand));
lPLCIncomingChannel.initialize();

SUPER^.initialize();

lPackSystem REF= packSystem;
lPackMovement REF= packMovement;
lPackReportable REF= packReportable;
lPackSpreader REF= packSpreader;

lPackUICommand REF= packUICommand;

lPackProvider REF= packProvider;

pullPLCIncomingChannel := FALSE;

lPackProvider.pull();

IF (lPLCIncomingPacket.Byte1<>lPackProvider.PackIn1) THEN
	lPLCIncomingPacket.Byte1 := lPackProvider.PackIn1;
	lPLCIncomingPacket.Byte1 := lPLCIncomingPacket.Byte1 OR INT_TO_USINT(cPackCodeUICommand);
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte2<>lPackProvider.PackIn2) THEN
	lPLCIncomingPacket.Byte2 := lPackProvider.PackIn2;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte3<>lPackProvider.PackIn3) THEN
	lPLCIncomingPacket.Byte3 := lPackProvider.PackIn3;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte4<>lPackProvider.PackIn4) THEN
	lPLCIncomingPacket.Byte4 := lPackProvider.PackIn4;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte5<>lPackProvider.PackIn5) THEN
	lPLCIncomingPacket.Byte5 := lPackProvider.PackIn5;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte6<>lPackProvider.PackIn6) THEN
	lPLCIncomingPacket.Byte6 := lPackProvider.PackIn6;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte7<>lPackProvider.PackIn7) THEN
	lPLCIncomingPacket.Byte7 := lPackProvider.PackIn7;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

IF (lPLCIncomingPacket.Byte8<>lPackProvider.PackIn8) THEN
	lPLCIncomingPacket.Byte8 := lPackProvider.PackIn8;
	gSystemPrimary.Active.registerUI();
	pullPLCIncomingChannel := TRUE;
END_IF

lPackProvider.PackOut1 := lPLCOutgoingPacket.Byte1;
lPackProvider.PackOut2 := lPLCOutgoingPacket.Byte2;
lPackProvider.PackOut3 := lPLCOutgoingPacket.Byte3;
lPackProvider.PackOut4 := lPLCOutgoingPacket.Byte4;
lPackProvider.PackOut5 := lPLCOutgoingPacket.Byte5;
lPackProvider.PackOut6 := lPLCOutgoingPacket.Byte6;
lPackProvider.PackOut7 := lPLCOutgoingPacket.Byte7;
lPackProvider.PackOut8 := lPLCOutgoingPacket.Byte8;

lPackProvider.push();

lPackTimer.operator();
IF ((NOT(lPackTimer.Enable)) OR (lPackTimer.Expired)) THEN
	lPackTimer.reset();

	lPLCOutgoingChannel.pack(lPLCOutgoingPacket);
	pushPLCOutgoingChannel();

	IF (lDebugPack) THEN
		lDebugPackPacket.copy(lPLCOutgoingPacket);
	END_IF
END_IF

IF (pullPLCIncomingChannel()) THEN
	IF (lDebugUnpack) THEN
		lDebugUnpackPacket.copy(lPLCIncomingPacket);
	END_IF

	lPLCIncomingChannel.unpack(lPLCIncomingPacket);
END_IF

lSteerStateA := packet.unpackUSINT(5,3);
lSteerStateB := packet.unpackUSINT(8,3);
lSteerStateC := packet.unpackUSINT(11,3);
lSteerStateD := packet.unpackUSINT(14,3);

lSteerTargetAngle := AngleFromSINT(packet.unpackSINT(17,8));
lSteerCurrentMode := USINT_TO_INT(packet.unpackUSINT(25,4));

lTravelActive := packet.unpackBool(29);
lTravelVelocity :=  SignedPercentageFrom6bits(packet.unpackUSINT(30,6));

lLiftActive := packet.unpackBool(36);
lLiftABPosition := SignedPercentageFrom7bits(packet.unpackUSINT(37,7));
lLiftCDPosition := SignedPercentageFrom7bits(packet.unpackUSINT(44,7));

lProgrammedMovementCurrent := packet.unpackUSINT(51,5);
lProgrammedMovementState := packet.unpackUSINT(56,3);

IF (packet.unpackBool(5)) THEN
	lReportableA.valid := TRUE;
	lReportableA.state := packet.unpackUSINT(6,8);
ELSE
	lReportableA.event := packet.unpackUSINT(6,8);
	IF (lReportableA.event=cECNone) THEN
		lReportableA.valid := FALSE;
		lReportableB.valid := FALSE;
		lReportableC.valid := FALSE;
		lReportableD.valid := FALSE;

		RETURN;				
	END_IF
	lReportableA.valid := TRUE;
END_IF
lReportableA.active := packet.unpackBool(14);
lReportableA.subsystem := packet.unpackUSINT(15,5);

IF (packet.unpackBool(20)) THEN
	lReportableB.valid := TRUE;
	lReportableB.state := packet.unpackUSINT(21,8);
ELSE
	lReportableB.event := packet.unpackUSINT(21,8);	
	IF (lReportableB.event=cECNone) THEN
		lReportableB.valid := FALSE;
		lReportableC.valid := FALSE;
		lReportableD.valid := FALSE;

		RETURN;				
	END_IF
	lReportableB.valid := TRUE;
END_IF
lReportableB.active := packet.unpackBool(29);
lReportableB.subsystem := packet.unpackUSINT(30,5);

IF (packet.unpackBool(35)) THEN
	lReportableC.valid := TRUE;
	lReportableC.state := packet.unpackUSINT(36,8);
ELSE
	lReportableC.event := packet.unpackUSINT(36,8);	
	IF (lReportableC.event=cECNone) THEN
		lReportableC.valid := FALSE;
		lReportableD.valid := FALSE;

		RETURN;				
	END_IF
	lReportableC.valid := TRUE;
END_IF
lReportableC.active := packet.unpackBool(44);
lReportableC.subsystem := packet.unpackUSINT(45,5);

IF (packet.unpackBool(50)) THEN
	lReportableD.valid := TRUE;
	lReportableD.state := packet.unpackUSINT(51,8);
ELSE
	lReportableD.event := packet.unpackUSINT(51,8);	
	IF (lReportableD.event=cECNone) THEN
		lReportableD.valid := FALSE;

		RETURN;				
	END_IF
	lReportableD.valid := TRUE;
END_IF
lReportableD.active := packet.unpackBool(59);
lReportableD.subsystem := packet.unpackUSINT(60,5);

IF (NOT(lReportableA.valid)) THEN
	RETURN;
END_IF

IF (lReportableA.event=cECNone) THEN
	packet.packBool(TRUE,5);
	packet.packUSINT(INT_TO_USINT(lReportableA.state),6,8);
ELSE
	packet.packBool(FALSE,5);
	packet.packUSINT(INT_TO_USINT(lReportableA.event),6,8);
END_IF
packet.packBool(lReportableA.active,14);
packet.packUSINT(INT_TO_USINT(lReportableA.subsystem),15,5);

IF (NOT(lReportableB.valid)) THEN
	RETURN;
END_IF

IF (lReportableB.event=cECNone) THEN
	packet.packBool(TRUE,20);
	packet.packUSINT(INT_TO_USINT(lReportableB.state),21,8);
ELSE
	packet.packBool(FALSE,20);
	packet.packUSINT(INT_TO_USINT(lReportableB.event),21,8);
END_IF
packet.packBool(lReportableB.active,29);
packet.packUSINT(INT_TO_USINT(lReportableB.subsystem),30,5);

IF (NOT(lReportableC.valid)) THEN
	RETURN;
END_IF

IF (lReportableC.event=cECNone) THEN
	packet.packBool(TRUE,35);
	packet.packUSINT(INT_TO_USINT(lReportableC.state),36,8);
ELSE
	packet.packBool(FALSE,35);
	packet.packUSINT(INT_TO_USINT(lReportableC.event),36,8);
END_IF
packet.packBool(lReportableC.active,44);
packet.packUSINT(INT_TO_USINT(lReportableC.subsystem),45,5);

IF (NOT(lReportableD.valid)) THEN
	RETURN;
END_IF

IF (lReportableD.event=cECNone) THEN
	packet.packBool(TRUE,50);
	packet.packUSINT(INT_TO_USINT(lReportableD.state),51,8);
ELSE
	packet.packBool(FALSE,50);
	packet.packUSINT(INT_TO_USINT(lReportableD.event),51,8);
END_IF
packet.packBool(lReportableD.active,59);
packet.packUSINT(INT_TO_USINT(lReportableD.subsystem),60,5);

SUPER^.reset();

lReportableA.valid := FALSE;
lReportableB.valid := FALSE;
lReportableC.valid := FALSE;
lReportableD.valid := FALSE;

lSideShiftActive := packet.unpackBool(5);

lTwistlocksState := packet.unpackUSINT(6,2);

lStateA := packet.unpackUSINT(8,2);
lLoweredA := packet.unpackBool(10);
lStateB := packet.unpackUSINT(11,2);
lLoweredB := packet.unpackBool(13);
lStateC := packet.unpackUSINT(14,2);
lLoweredC := packet.unpackBool(16);
lStateD := packet.unpackUSINT(17,2);
lLoweredD := packet.unpackBool(19);

lExtensionState := packet.unpackUSINT(20,2);
lSpreaderOperationEnabled := packet.unpackBool(22);
lSpreaderOperationActive := packet.unpackBool(23);

lSpreaderConfigurationOptionEnabled := packet.unpackBool(24);
lSpreaderConfigurationEnabled := packet.unpackBool(25);
lSpreaderConfigurationActive := packet.unpackBool(26);
lSpreaderConfigurationExtending := packet.unpackBool(27);
lSpreaderConfigurationRetracting := packet.unpackBool(28);

lTopbeamActive := packet.unpackBool(29);
lTopbeamABPosition := SignedPercentageFrom7bits(packet.unpackUSINT(30,7));
lTopbeamCDPosition := SignedPercentageFrom7bits(packet.unpackUSINT(37,7));

packet.packBool(lSideShiftActive,5);

//6-32 27 bits

packet.packUSINT(INT_TO_USINT(lTwistlocksState),6,2);

packet.packUSINT(INT_TO_USINT(lStateA),8,2);
packet.packBool(lLoweredA,10);
packet.packUSINT(INT_TO_USINT(lStateB),11,2);
packet.packBool(lLoweredB,13);
packet.packUSINT(INT_TO_USINT(lStateC),14,2);
packet.packBool(lLoweredC,16);
packet.packUSINT(INT_TO_USINT(lStateD),17,2);
packet.packBool(lLoweredD,19);

packet.packUSINT(INT_TO_USINT(lExtensionState),20,2);
packet.packBool(lSpreaderOperationEnabled,22);
packet.packBool(lSpreaderOperationActive,23);

packet.packBool(lSpreaderConfigurationOptionEnabled,24);
packet.packBool(lSpreaderConfigurationEnabled,25);
packet.packBool(lSpreaderConfigurationActive,26);
packet.packBool(lSpreaderConfigurationExtending,27);
packet.packBool(lSpreaderConfigurationRetracting,28);

packet.packBool(lTopbeamActive,29);
packet.packUSINT(SignedPercentageAs7bits(lTopbeamABPosition),30,7);
packet.packUSINT(SignedPercentageAs7bits(lTopbeamCDPosition),37,7);

lFunctionalMode := packet.unpackUSINT(5,3);
lToggle := packet.unpackBool(8);
lSystemState := packet.unpackUSINT(9,4);
lOperatingMode := packet.unpackUSINT(13,4);
lSpeedModeSlow := packet.unpackBool(17);
lLightStatus := packet.unpackBool(18);
lUIReady := packet.unpackBool(19);
lUIModeRequest := packet.unpackBool(20);
lUIMode := packet.unpackUSINT(21,2);
lHours := packet.unpackUINT(23,16);
lSOC := PercentageFrom7bits(packet.unpackUSINT(39,7));
lCurrent := SignedPercentageFrom8bits(packet.unpackUSINT(46,8));
lInputMode := packet.unpackUSINT(54,2);
lUIOrientation := packet.unpackUSINT(56,3);
lAvailability := PercentageFrom4bits(packet.unpackUSINT(59,4));

IF (lOverrideSystemState) THEN
	lSystemState := lOverrideSystemStateValue;
END_IF

packet.packUSINT(INT_TO_USINT(lFunctionalMode),5,3);
packet.packBool(lToggle,8);
packet.packUSINT(INT_TO_USINT(lSystemState),9,4);
packet.packUSINT(INT_TO_USINT(lOperatingMode),13,4);
packet.packBool(lSpeedModeSlow,17);
packet.packBool(lLightStatus,18);
packet.packBool(lUIReady,19);
packet.packBool(lUIModeRequest,20);
packet.packUSINT(INT_TO_USINT(lUIMode),21,2);
packet.packUINT(lHours,23,16);
packet.packUSINT(PercentageAs7bits(lSOC),39,7);
packet.packUSINT(SignedPercentageAs8bits(lCurrent),46,8);
packet.packUSINT(INT_TO_USINT(lInputMode),54,2);
packet.packUSINT(INT_TO_USINT(lUIOrientation),56,3);
packet.packUSINT(PercentageAs4bits(lAvailability),59,4);

SUPER^.reset();

lUIModeResponse := FALSE;
lUIEventCodeRequest := cUIEventCodeNone;
lSteerModeRequest := cSteerModeNone;
lOperatingMethodRequest := cOperatingMethodNone;
lFunctionalModeRequest := cFunctionalModeAny;
lInputModeRequest := cInputModeNone;
lAutomationRequest := cProgMovCodeNone;
lIsBeginner := FALSE;

lReportableA.valid := FALSE;
lReportableB.valid := FALSE;

