lFunctionalModeRequest := packet.unpackUSINT(18,3);
lInputModeRequest := packet.unpackUSINT(21,2);
lUIOrientationRequest := packet.unpackUSINT(23,3);
lAutomationRequest := packet.unpackUSINT(26,5);
lIsBeginner := packet.unpackBool(31);
lOverride := packet.unpackBool(32);

IF (packet.unpackBool(33)) THEN
	lReportableA.valid := TRUE;
	lReportableA.state := packet.unpackUSINT(34,8);
ELSE
	lReportableA.event := packet.unpackUSINT(34,8);
	IF (lReportableA.event=cECNone) THEN
		lReportableA.valid := FALSE;
		lReportableB.valid := FALSE;

		RETURN;				
	END_IF
	lReportableA.valid := TRUE;
END_IF
lReportableA.active := packet.unpackBool(42);
lReportableA.subsystem := packet.unpackUSINT(43,5);

