packet.packUSINT(INT_TO_USINT(lUIOrientationRequest),23,3);
packet.packUSINT(INT_TO_USINT(lAutomationRequest),26,5);
packet.packBool(lIsBeginner,31);
packet.packBool(lOverride,32);

IF (NOT(lReportableA.valid)) THEN
	RETURN;
END_IF

IF (lReportableA.event=cECNone) THEN
	packet.packBool(TRUE,33);
	packet.packUSINT(INT_TO_USINT(lReportableA.state),34,8);
ELSE
	packet.packBool(FALSE,33);
	packet.packUSINT(INT_TO_USINT(lReportableA.event),34,8);
END_IF
packet.packBool(lReportableA.active,42);
packet.packUSINT(INT_TO_USINT(lReportableA.subsystem),43,5);

